 401→### Task 4: Create db/mod.rs — DbHandle + Connection Factory
 402→
 403→This is the core rewrite. DbHandle changes from `Arc<Mutex<FactoryDb>>` to a thin wrapper around `libsql::Database`.
 404→
 405→**Files:**
 406→- Create: `src/factory/db/mod.rs`
 407→
 408→**Step 1: Write the new DbHandle**
 409→
 410→```rust
 411→pub mod agents;
 412→pub mod issues;
 413→pub mod migrations;
 414→pub mod pipeline;
 415→pub mod projects;
 416→pub mod settings;
 417→
 418→use std::path::Path;
 419→use std::time::Duration;
 420→
 421→use anyhow::{Context, Result};
 422→use libsql::{Builder, Connection, Database};
 423→
 424→/// Async database handle wrapping a libsql Database.
 425→///
 426→/// Supports two modes:
 427→/// - **Turso embedded replica** when TURSO_DATABASE_URL and TURSO_AUTH_TOKEN are set
 428→/// - **Local SQLite** otherwise (dev/offline fallback)
 429→#[derive(Clone)]
 430→pub struct DbHandle {
 431→    db: Database,
 432→}
 433→
 434→impl DbHandle {
 435→    /// Open a local-only SQLite database at the given path.
 436→    pub async fn new_local(path: &Path) -> Result<Self> {
 437→        let path_str = path.to_string_lossy().to_string();
 438→        let db = Builder::new_local(&path_str)
 439→            .build()
 440→            .await
 441→            .context("Failed to open local SQLite database")?;
 442→        let handle = Self { db };
 443→        handle.init().await?;
 444→        Ok(handle)
 445→    }
 446→
 447→    /// Open a Turso embedded replica with local file cache.
 448→    pub async fn new_remote_replica(
 449→        local_path: &Path,
 450→        url: &str,
 451→        token: &str,
 452→    ) -> Result<Self> {
 453→        let path_str = local_path.to_string_lossy().to_string();
 454→        let db = Builder::new_remote_replica(&path_str, url, token)
 455→            .sync_interval(Duration::from_secs(60))
 456→            .read_your_writes(true)
 457→            .build()
 458→            .await
 459→            .context("Failed to open Turso embedded replica")?;
 460→        let handle = Self { db };
 461→        handle.init().await?;
 462→        Ok(handle)
 463→    }
 464→
 465→    /// Open an in-memory database (for testing).
 466→    pub async fn new_in_memory() -> Result<Self> {
 467→        let db = Builder::new_local(":memory:")
 468→            .build()
 469→            .await
 470→            .context("Failed to open in-memory database")?;
 471→        let handle = Self { db };
 472→        handle.init().await?;
 473→        Ok(handle)
 474→    }
 475→
 476→    /// Get a new connection from the database.
 477→    pub fn conn(&self) -> Result<Connection> {
 478→        self.db.connect().context("Failed to get database connection")
 479→    }
 480→
 481→    /// Sync embedded replica with remote (no-op for local-only).
 482→    pub async fn sync(&self) -> Result<()> {
 483→        // sync() returns a result with replication info; we just need it to succeed
 484→        let _ = self.db.sync().await;
 485→        Ok(())
 486→    }
 487→
 488→    /// Initialize pragmas and run migrations.
 489→    async fn init(&self) -> Result<()> {
 490→        let conn = self.conn()?;
 491→        init_pragmas(&conn).await?;
 492→        migrations::run_migrations(&conn).await?;
 493→        Ok(())
 494→    }
 495→}
 496→
 497→/// Set WAL mode, busy timeout, and enable foreign keys.
 498→async fn init_pragmas(conn: &Connection) -> Result<()> {
 499→    conn.execute("PRAGMA journal_mode=WAL", ())
 500→        .await
 501→        .context("Failed to set WAL mode")?;
 502→    conn.execute("PRAGMA busy_timeout=5000", ())
 503→        .await
 504→        .context("Failed to set busy_timeout")?;
 505→    conn.execute("PRAGMA foreign_keys=ON", ())
 506→        .await
 507→        .context("Failed to enable foreign keys")?;
 508→    Ok(())
 509→}
 510→
 511→/// Run integrity check on startup. Logs warning but does not fail.
 512→pub async fn health_check(conn: &Connection) {
 513→    match conn.query("PRAGMA integrity_check", ()).await {
 514→        Ok(mut rows) => {
 515→            if let Ok(Some(row)) = rows.next().await {
 516→                if let Ok(result) = row.get::<String>(0) {
 517→                    if result != "ok" {
 518→                        tracing::warn!("Database integrity check failed: {result}");
 519→                    }
 520→                }
 521→            }
 522→        }
 523→        Err(e) => {
 524→            tracing::warn!("Failed to run integrity check: {e}");
 525→        }
 526→    }
 527→}
 528→```
