 29→impl DbHandle {
 30→    /// Open a local-only SQLite database at the given path.
 31→    pub async fn new_local(path: &Path) -> Result<Self> {
 32→        let path_str = path.to_string_lossy().to_string();
 33→        let db = Builder::new_local(&path_str)
 34→            .build()
 35→            .await
 36→            .context("Failed to open local SQLite database")?;
 37→        Self::from_db(db).await
 38→    }
