 40→    /// Open a Turso embedded replica with local file cache.
 41→    pub async fn new_remote_replica(
 42→        local_path: &Path,
 43→        url: &str,
 44→        token: &str,
 45→    ) -> Result<Self> {
 46→        let path_str = local_path.to_string_lossy().to_string();
 47→        let db = Builder::new_remote_replica(
 48→            &path_str,
 49→            url.to_string(),
 50→            token.to_string(),
 51→        )
 52→        .sync_interval(Duration::from_secs(60))
 53→        .read_your_writes(true)
 54→        .build()
 55→        .await
 56→        .context("Failed to open Turso embedded replica")?;
 57→        Self::from_db(db).await
 58→    }
